/**
 * Find the common parent of two node pointers.
 *
 * @param p1 the first node pointer
 * @param depth1 the depth of the first node pointer
 * @param p2 the second node pointer
 * @param depth2 the depth of the second node pointer
 * @return the common parent node pointer
 * @throws JXPathException if the pointers do not belong to the same tree
 */
private int compareNodePointers(NodePointer p1, int depth1, NodePointer p2, int depth2) {
    if (p1.parent == null || p2.parent == null) return 0;
    if (depth1 < depth2) {
        int r = compareNodePointers(p1, depth1, p2.parent, depth2 - 1);
        return r == 0 ? -1 : r;
    }
    if (depth1 > depth2) {
        int r = compareNodePointers(p1.parent, depth1 - 1, p2, depth2);
        return r == 0 ? 1 : r;
    }
    if (p1.equals(p2)) {
        return 0;
    }
    int r = compareNodePointers(p1.parent, depth1 - 1, p2.parent, depth2 - 1);
    if (r != 0) {
        return r;
    }
    return p1.parent.compareChildNodePointers(p1, p2);
}

